CODE_EXAMPLE:
// Before
new Employee("Senior");

// After
Employee create(String type) {
  if (type.equals("Senior")) {
    return new SeniorEmployee();
  }
  return new JuniorEmployee();
}

// Call
Employee.create("Senior");

UNIT_TEST_EXAMPLE:
@Test
public void testFactoryMethod() {
  Employee senior = Employee.create("Senior");
  assertTrue(senior instanceof SeniorEmployee);
}
